mapper.select:
SELECT COALESCE(SUM(total_amount), 0)
FROM `bls_order`
WHERE DATE(create_time) = #{date}

    AND store_id IN

        #{storeId}


AND status = 'COMPLETED'

SELECT COUNT(*)
FROM `bls_order`
WHERE DATE(create_time) = #{date}

    AND store_id IN

        #{storeId}


AND status = 'COMPLETED'

WITH bls_table_usage AS (
    SELECT
        COUNT(*) * 100.0 / (
            SELECT COUNT(*)
            FROM bls_table
            WHERE is_delete = 0

                AND store_id IN

                    #{storeId}


        ) as usage_rate
    FROM bls_table_usage
    WHERE DATE(start_time) = #{date}

        AND store_id IN

            #{storeId}


    AND status = 'COMPLETED'
)
SELECT COALESCE(usage_rate, 0) FROM bls_table_usage

SELECT COUNT(*) FROM bls_user WHERE DATE(create_time) = #{date}
AND store_id IN
#{storeId}
AND is_delete = 0 AND is_member = 1

SELECT HOUR(create_time) as hour, COUNT(*) as orderCount, COALESCE(SUM(total_amount), 0) as hourlyRevenue FROM `bls_order` WHERE DATE(create_time) = #{date}
AND store_id IN
#{storeId}
AND status = 'COMPLETED' GROUP BY HOUR(create_time) ORDER BY hour

SELECT t.id as tableId, t.table_number as tableNumber, t.store_id as storeId, s.name as storeName, COUNT(tu.id) as usageCount, COALESCE(SUM(tu.duration), 0) as totalDuration, COALESCE(SUM(o.total_amount), 0) as totalRevenue FROM bls_table t JOIN bls_store s ON t.store_id = s.id LEFT JOIN bls_table_usage tu ON t.id = tu.table_id AND DATE(tu.start_time) BETWEEN #{startDate} AND #{endDate} AND tu.status = 'COMPLETED' LEFT JOIN `bls_order` o ON tu.order_id = o.id AND o.status = 'COMPLETED' WHERE t.is_delete = 0
AND t.store_id IN
#{storeId}
GROUP BY t.id, t.table_number, t.store_id, s.name ORDER BY totalRevenue DESC LIMIT #{limit}
